function calcBruto(empleado) {
  let bruto = empleado.salarioBase;
  if (empleado.horas > 40) {
    const extras = empleado.horas - 40;
    bruto = bruto + extras * empleado.tarifa * 1.5;
  }
  return bruto;
}

function calcNeto(bruto) {
  const salud = bruto * 0.04;
  const pension = bruto * 0.04;
  const retencion = bruto > 5000 ? bruto * 0.10 : 0;
  return bruto - salud - pension - retencion;
}

function calcularLiquidacion(empleado) {
  const bruto = calcBruto(empleado);
  const neto = calcNeto(bruto);
  return { neto, bruto };
}

