const emp = { nombre: 'Ana', salarioBase: 3000, horas: 40, tarifa: 50 };
const r = calcularLiquidacion(emp);
const esperado = 3000 - 3000 * 0.04 - 3000 * 0.04;
if (Math.abs(r.neto - esperado) > 0.01)
  throw new Error('Neto esperado ' + esperado + ', recibido ' + r.neto);

const emp = { nombre: 'Beto', salarioBase: 3000, horas: 45, tarifa: 50 };
const r = calcularLiquidacion(emp);
const bruto = 3000 + 5 * 50 * 1.5;
const esperado = bruto - bruto * 0.04 - bruto * 0.04;
if (Math.abs(r.neto - esperado) > 0.01)
  throw new Error('Neto esperado ' + esperado + ', recibido ' + r.neto);

